    Integer duration
    Integer number
    Integer maxVisitors = 20
    Decimal discount
}

class Person {
    String name
}

City "1" -- "*" Attraction : has
Attraction "1" -- "*" GuidedTour : offers
GuidedTour "1" -- "1" Person : requires
GuidedTour "*" -- "*" Person : includes

@enduml

cprompt:
[
  {
    "role": "user",
    "content": "\nCode in PlantUML the following task: Every city has several attractions. A city has a name and a specific number of inhabitants, while an attraction has a name and an address. Various guided tours are offered for a tourist attraction, and the duration and number of a guided tour are known. A maximum of 20 visitors can take part in a guided tour, and certain visitors may be granted a discount for certain guided tours; the amount of this discount must be known. Of course, a guided tour also requires a guide. The visitors and the guide are people who have names.\n\nIt is only a plain domain model definition, therefore follow these instructions carefully:\n1. Only use the UML valid data types: String, Integer, Date, Boolean, Decimal.\n2. There are no private or public attributes. \n3. Usually there are no methods defined, because it is just a domain model definition.\n\nDo not include explanations, examples, usage demonstrations or any commentaries in the code.\n                "
  },
  {
    "role": "assistant",
    "content": "{\"code\":\"\\n@startuml\\n\\nclass City {\\n    String name\\n    Integer inhabitants\\n}\\n\\nclass Attraction {\\n    String name\\n    String address\\n}\\n\\nclass GuidedTour {\\n    Integer duration\\n    Integer number\\n    Integer maxVisitors = 20\\n    Decimal discount\\n}\\n\\nclass Person {\\n    String name\\n}\\n\\nCity \\\"1\\\" -- \\\"*\\\" Attraction : has\\nAttraction \\\"1\\\" -- \\\"*\\\" GuidedTour : offers\\nGuidedTour \\\"1\\\" -- \\\"1\\\" Person : requires\\nGuidedTour \\\"*\\\" -- \\\"*\\\" Person : includes\\n\\n@enduml\\n\"}"
  }
]

