    "role": "assistant",
    "content": "{\"code\":\"\\n@startuml\\n\\nclass House {\\n    String address\\n    String buildingMaterial\\n    Boolean hasBasement\\n}\\n\\nclass Basement {\\n    String name\\n    Integer size\\n}\\n\\nclass EarthBasement extends Basement {\\n    Decimal humidityLevel\\n}\\n\\nclass ConcreteBasement extends Basement {\\n}\\n\\nclass SemiDetachedHouse extends House {\\n    Boolean hasGarden\\n    Integer numberOfWindows\\n    Boolean hasCarports\\n    Boolean hasGarage\\n}\\n\\nclass Carport {\\n    Boolean isDouble\\n    Boolean hasFlatRoof\\n}\\n\\nclass Garage {\\n    Boolean hasAutomaticDoor\\n}\\n\\nclass Company {\\n    String name\\n    String address\\n}\\n\\nclass JobLog {\\n    Integer hours\\n    Decimal agreedPrice\\n}\\n\\nHouse \\\"1\\\" -- \\\"0..1\\\" Basement : has\\nSemiDetachedHouse \\\"1\\\" -- \\\"0..2\\\" Carport : has\\nSemiDetachedHouse \\\"1\\\" -- \\\"0..1\\\" Garage : has\\nHouse \\\"1\\\" -- \\\"*\\\" Company : serviced by\\nCompany \\\"1\\\" -- \\\"*\\\" JobLog : logs\\n\\n@enduml\\n\"}"
  }
]

